class Solution {
public:
    int maxFreq(string s, int maxLetters, int minSize, int maxSize) {
        int count[26] = {0}; // 26 characters from 'a' to 'z'
        int freq[26] = {0}; // frequency of each character

        for (char c : s) {
            count[c - 'a']++;
            freq[c - 'a']++;
        }

        int max_freq = 0;
        for (int i = 0; i < 26; i++) {
            if (freq[i] <= maxLetters && count[i] >= minSize && count[i] <= maxSize) {
                max_freq = max(max_freq, freq[i]);
            }
        }

        return max_freq;
    }
};
